#!/usr/bin/env python
"""
Bootstrap: Phases 3-6 Energy Harvesting Stack
  Phase 3: Click Interface Electrical Model
  Phase 4: Active Building Element Profiles
  Phase 5: 4-Objective Harvesting Pareto
  Phase 6: Harvesting Safety Integration

Requires Phase 1+2 bootstraps applied first.

Usage: python bootstrap_harvesting_phases3_6.py
  (run from MABE repo root)
"""

import base64, os, sys

# Root detection
if os.path.isfile("core/universal_schema.py"):
    root = "."
elif os.path.isfile(os.path.join("..", "core", "universal_schema.py")):
    root = ".."
    os.chdir(root)
else:
    print("ERROR: Run from MABE repo root (must contain core/universal_schema.py)")
    sys.exit(1)

# Check Phase 1+2 prerequisites
for prereq in ["core/conductive_base.py", "core/energy_harvesting.py"]:
    if not os.path.isfile(prereq):
        print(f"ERROR: {prereq} not found. Apply Phase 1+2 bootstraps first.")
        sys.exit(1)

FILES = {
    'core/click_interface.py': '',
    'tests/test_click_interface.py': '',
    'core/active_element_profiles.py': '',
    'tests/test_active_element_profiles.py': '',
    'core/harvesting_pareto.py': '',
    'tests/test_harvesting_pareto.py': '',
    'core/harvesting_safety.py': '',
    'tests/test_harvesting_safety.py': '',
}

for path, b64 in FILES.items():
    os.makedirs(os.path.dirname(path), exist_ok=True)
    content = base64.b64decode(b64).decode("utf-8")
    with open(path, "w", encoding="utf-8") as f:
        f.write(content)
    print(f"  Wrote {path} ({len(content)} bytes)")

print("")
print("Done. Run:")
print("  python -m pytest tests/test_click_interface.py tests/test_active_element_profiles.py tests/test_harvesting_pareto.py tests/test_harvesting_safety.py -v")